INSERT INTO public.home_page VALUES ('HOME', '{"badge": "منصة سحابية للتطوير العقاري", "title": "إدارة مشاريعك العقارية", "subtitle": "أيسَر تمنحك لوحة تحكم احترافية لإدارة مشاريعك وعملاءك — من تتبع مراحل الإنشاء وإشعارات فورية، حتى صفحات هبوط واستقبال حجوزات ونظام CRM متكامل.", "titleAccent": "بسهولة وشفافية كاملة", "primaryCtaHref": "#", "primaryCtaLabel": "اطلب تجربة مجانية", "secondaryCtaHref": "#features", "secondaryCtaLabel": "اكتشف المميزات"}', '[{"title": "تتبع مراحل الإنشاء", "layout": "text-left", "eyebrow": "01 — تتبع مراحل الإنشاء", "features": ["صور وفيديو — من الموقع ترفعها الفرق مباشرة", "إشعارات فورية — عند كل تحديث لكل مرحلة", "قوالب مرنة — تصل إلى 50 مرحلة وتعدّلها كما تشاء"], "accentColor": "#2d2e83", "description": "يتيح أيسَر متابعة دقيقة لكل مراحل تنفيذ العقار — من الحفر حتى التسليم. المنصة تأتي بقوالب جاهزة تصل إلى 50 مرحلة قابلة للتعديل بالكامل حسب مشروعك.", "titleAccent": "خطوة بخطوة"}, {"title": "بلاغات الصيانة", "layout": "text-right", "eyebrow": "02 — إدارة طلبات الصيانة", "features": ["إشعار فوري — عند رفع أي بلاغ جديد", "تتبع الحالة — من مفتوح حتى الإغلاق", "تعيين موظف — مسؤول لكل بلاغ", "سجل كامل — لكل طلبات الصيانة"], "accentColor": "#ef4444", "description": "بعد التسليم، يمكن للعميل تقديم بلاغات الصيانة بشكل مباشر عبر التطبيق. يتم توجيهها فورًا إلى حسابك وتستطيع متابعة حالة الطلب حتى الإغلاق.", "titleAccent": "بضغطة واحدة"}, {"title": "استقبل الحجوزات", "layout": "text-left", "eyebrow": "03 — استقبال الحجوزات", "features": ["صفحة هبوط — مخصصة لكل مشروع برابط خاص", "نموذج حجز — مدمج يصل تلقائياً للوحة التحكم", "إضافة يدوية — للعملاء المباشرين بثوانٍ", "CRM متكامل — لإدارة pipeline المبيعات"], "accentColor": "#f97316", "description": "صفحات هبوط مخصصة لكل مشروع مع نموذج حجز مدمج — الحجوزات تصل تلقائياً للوحة التحكم. وإذا جاء عميل مباشرة أضفه يدوياً في ثوانٍ، ثم أدر الكل من CRM واحد.", "titleAccent": "من كل مكان"}, {"title": "قوالب جاهزة", "layout": "text-right", "eyebrow": "04 — القوالب الجاهزة", "features": ["قوالب جاهزة — لكل أنواع المشاريع العقارية", "50 مرحلة — قابلة للتعديل الكامل حسب مشروعك", "ترتيب بالسحب والإفلات — لإعادة ترتيب المراحل", "صور وفيديو — لكل مرحلة ترفعها الفرق مباشرة"], "accentColor": "#f97316", "description": "لا تبدأ من الصفر — أيسَر يوفر قوالب مراحل جاهزة لكل أنواع المشاريع. استورد القالب، عدّل المراحل حسب مشروعك، وابدأ فوراً.", "titleAccent": "تصل إلى 50 مرحلة"}]', '[{"title": "إشعارات لحظية", "iconBg": "#e9f9f0", "iconName": "Bell", "iconColor": "#1a9a5a", "description": "عند كل تحديث للمراحل"}, {"title": "صفحات هبوط", "iconBg": "#eef2ff", "iconName": "Globe", "iconColor": "#4f46e5", "description": "برابط خاص لكل مشروع"}, {"title": "نظام CRM", "iconBg": "#f0f4ff", "iconName": "Users", "iconColor": "#2d2e83", "description": "إدارة العملاء والمبيعات"}, {"title": "تطبيق مخصص", "iconBg": "#fff7ed", "iconName": "Smartphone", "iconColor": "#f97316", "description": "iOS و Android للعملاء"}, {"title": "صور وفيديو", "iconBg": "#fdf2f8", "iconName": "ImageIcon", "iconColor": "#ec4899", "description": "توثيق المراحل من الموقع"}, {"title": "سحابي 100%", "iconBg": "#e7fafd", "iconName": "Cloud", "iconColor": "#06b6d4", "description": "بدون تثبيت أو خوادم"}, {"title": "مشاريع متعددة", "iconBg": "#f3eefe", "iconName": "LayoutGrid", "iconColor": "#8b5cf6", "description": "فيلات، شقق، تجاري"}, {"title": "دعم فني 7/24", "iconBg": "#fff8e8", "iconName": "MessageCircle", "iconColor": "#f59e0b", "description": "واتساب أو بريد إلكتروني"}]', '{"title": "كل مشاريعك", "eyebrow": "لوحة التحكم", "linkHref": "https://platform.aysar.sa/", "linkLabel": "ادخل لوحة التحكم", "checkItems": [{"bold": "إدارة مشاريع متعددة", "detail": " — فيلات، شقق، تجاري من لوحة واحدة"}, {"bold": "تتبع نسبة الإنجاز", "detail": " لكل مشروع ولكل مرحلة بدقة"}, {"bold": "توثيق بالصور والفيديو", "detail": " — يراها العميل فور رفعها"}, {"bold": "سحابي 100%", "detail": " — من أي جهاز وأي مكان بدون تثبيت"}], "description": "لوحة تحكم احترافية تعطيك صورة كاملة عن جميع مشاريعك، وحداتك، وعملاءك — محدّثة لحظياً.", "titleAccent": "في