: "✓"}, {"section": "قادم قريباً"}, {"free": "قريباً", "label": "إدارة المدفوعات والمستحقات", "advanced": null, "featured": "قريباً"}, {"free": "قريباً", "label": "التوقيع الإلكتروني المعتمد", "advanced": null, "featured": "قريباً"}, {"free": "قريباً", "label": "نظام الفواتير والضرائب", "advanced": null, "featured": "قريباً"}, {"section": "الدعم الفني"}, {"free": "✓", "label": "دعم عبر البريد الإلكتروني", "advanced": "✓", "featured": "✓"}, {"free": null, "label": "دعم مباشر (هاتف + محادثة)", "advanced": "✓", "featured": "✓"}, {"free": "✓", "label": "مدير حساب شخصي", "advanced": null, "featured": "✓"}, {"free": null, "label": "تدريب مجاني للفريق", "advanced": "جلسة واحدة", "featured": "جلسات متعددة"}]', '[{"answer": "نعم، يمكنك الترقية في أي وقت من لوحة التحكم. ستُحتسب الرسوم بشكل تناسبي من تاريخ الترقية.", "question": "هل يمكنني الترقية من الباقة المجانية في أي وقت؟"}, {"answer": "الاشتراك السنوي يوفر لك 15% مقارنةً بالشهري. يُدفع مرة واحدة في السنة ويشمل جميع المميزات نفسها.", "question": "ما الفرق بين الاشتراك الشهري والسنوي؟"}, {"answer": "نعم، جميع الأسعار المعروضة شاملة ضريبة القيمة المضافة بنسبة 15%.", "question": "هل الأسعار شاملة الضريبة؟"}, {"answer": "نعم، تدعم أيسَر أنواعاً متعددة من المشاريع: فيلات، شقق، مجمعات سكنية، مبانٍ تجارية، ومشاريع متعددة النماذج.", "question": "هل يمكن استخدام المنصة لأنواع مختلفة من المشاريع العقارية؟"}, {"answer": "لا. التطبيق مجاني تماماً للملاك والمستثمرين. أنت كمطور عقاري تدفع الاشتراك، وعملاؤك يستخدمون التطبيق مجاناً.", "question": "هل يحتاج العملاء (الملاك) إلى دفع أي رسوم؟"}, {"answer": "يمكنك إلغاء اشتراكك في أي وقت من لوحة التحكم أو بالتواصل مع فريق الدعم. تبقى بياناتك محفوظة لمدة 30 يوماً بعد الإلغاء.", "question": "كيف تتم عملية الإلغاء؟"}]', '2026-05-24 01:22:39.182', '{"badge": "الأسعار والباقات", "title": "اختر الباقة", "subtitle": "باقات مرنة تساعدك على إدارة مشاريعك العقارية بكفاءة عالية — ابدأ مجاناً وطوّر متى تريد.", "titleAccent": "المناسبة لك"}');


