INSERT INTO public.policies VALUES ('POLICIES', '{"badge": "آخر تحديث: مايو 2025", "parts": [{"id": "sec-intro", "content": "<p>هذه الاتفاقية (\"الشروط\") مبرمة بين <strong>مؤسسة أيسر المتطورة لتقنية المعلومات</strong> (\"أيسَر\"، \"نحن\"، \"الشركة\")، ومقرها المملكة العربية السعودية، رقم السجل التجاري: 4030620045 — وبين الشخص الطبيعي أو الاعتباري الذي يستخدم المنصة (\"المستخدم\"، \"أنت\").</p>\n<p>تشمل \"المنصة\" موقع أيسَر الإلكتروني، تطبيق الجوال، لوحة تحكم المطوّر، نظام CRM، وجميع الخدمات والأدوات المرتبطة.</p>\n<div class=\"alert-card blue\"><div class=\"alert-icon\">&#x2139;&#xFE0F;</div><div class=\"alert-body\"><strong>للعلم</strong><p>تُعدّ هذه الشروط ملزمة لجميع مستخدمي المنصة بمجرد التسجيل أو البدء في الاستخدام، بصرف النظر عن طريقة الوصول.</p></div></div>", "headline": "تعريف الأطراف والمنصة"}, {"id": "sec-accept", "content": "<p>للاشتراك في منصة أيسَر والاستفادة من خدماتها يجب استيفاء الشروط التالية:</p>\n<ul class=\"policy-list\"><li>أن يكون المستخدم شركة أو مؤسسة أو شخصاً اعتبارياً مرخّصاً لمزاولة نشاط التطوير العقاري في المملكة العربية السعودية.</li><li>تقديم بيانات تسجيل صحيحة وكاملة وحديثة، والالتزام بتحديثها فور حدوث أي تغيير.</li><li>الحفاظ على سرية بيانات الدخول (اسم المستخدم وكلمة المرور) وعدم مشاركتها مع أطراف غير مخوّلة.</li><li>قبول هذه الشروط وسياسة الخصوصية بشكل صريح قبل بدء الاستخدام.</li><li>ألا يكون المستخدم قد سبق إيقاف حسابه أو حظره من المنصة لأي سبب.</li></ul>\n<p>تتحمل المنشأة المُسجَّلة المسؤولية الكاملة عن جميع الأنشطة التي تجري تحت حسابها، بما في ذلك تصرفات موظفيها ومستخدميها الفرعيين.</p>", "headline": "شروط القبول والتسجيل"}, {"id": "sec-use", "content": "<p>تُتيح منصة أيسَر للمستخدمين استخدام خدماتها ضمن النطاق التالي حصراً:</p>\n<ul class=\"policy-list\"><li>إدارة المشاريع العقارية وتتبع مراحل الإنشاء وتحديثها.</li><li>التواصل مع العملاء والمشترين وإدارة علاقاتهم عبر نظام CRM المدمج.</li><li>إنشاء صفحات هبوط احترافية واستقبال الحجوزات الإلكترونية.</li><li>إصدار الإشعارات والتقارير الإنشائية الدورية وتوزيعها على العملاء.</li><li>إدارة طلبات الصيانة ومتابعة تنفيذها بعد التسليم.</li><li>الاستفادة من التقارير والإحصاءات التحليلية لاتخاذ قرارات مدروسة.</li></ul>\n<div class=\"alert-card green\"><div class=\"alert-icon\">&#x2705;</div><div class=\"alert-body\"><strong>استخدام مشروع</strong><p>يقتصر الاستخدام المصرّح به على الأنشطة التجارية العقارية المشروعة والمتوافقة مع أنظمة المملكة العربية السعودية.</p></div></div>", "headline": "الاستخدام المسموح به"}, {"id": "sec-forbidden", "content": "<p>يُحظر على المستخدمين القيام بالأنشطة التالية أو السماح بها تحت أي ظرف:</p>\n<ul class=\"policy-list\"><li>نسخ المنصة أو أجزاء منها أو إعادة إنتاجها أو توزيعها دون إذن كتابي مسبق.</li><li>محاولة الوصول غير المصرّح به إلى أنظمة أيسَر أو بيانات مستخدمين آخرين.</li><li>استخدام المنصة لأغراض احتيالية أو مضللة أو مخالفة للأنظمة السعودية.</li><li>نشر أو إدخال برمجيات خبيثة أو محتوى ضار بأي شكل من الأشكال.</li><li>الاستخراج الآلي للبيانات (Scraping) أو استخدام واجهات برمجية غير رسمية دون إذن.</li><li>إعادة بيع الخدمة أو منح حق الوصول إليها لأطراف خارج المنشأة المشتركة.</li><li>التحايل على أي قيود تقنية أو إجراءات أمان مطبّقة على المنصة.</li></ul>\n<div class=\"alert-card amber\"><div class=\"alert-icon\">&#x26A0;&#xFE0F;</div><div class=\"alert-body\"><strong>تحذير</strong><p>يُفضي انتهاك أي من هذه المحظورات إلى إيقاف الحساب فوراً دون إشعار مسبق، وقد تتخذ أيسَر الإجراءات القانونية اللازمة.</p></div></div>", "headline": "الاستخدامات المحظورة"}, {"id": "sec-data", "content": "<p>تُعدّ جميع البيانات التي تُدخلها في المنصة ملكاً للمستخدم، وتلتزم أيسَر بحمايتها والحفاظ على سريتها وفقاً لسياسة الخصوصية المعتمدة ونظام حماية البيانات الشخصية في المملكة العربية السعودية (PDPL).</p>\n<ul class=\"policy-list\"><li>تُخزَّن البيانات على خوادم آمنة داخل المملكة العربية السعودية.</li><li>لا تُباع بيانات المستخدمين أو تُشارَك مع أطراف ثالثة لأغراض تجارية.</li><li>يحق للمستخدم طلب نسخة من بياناته أو حذفها وفق ما تتيحه سياسة الخصوصية.</li><li>تُطبَّق تقنيات تشفير متقدمة لحماية البيانات أثناء النقل والتخزين.</li></ul>\n<p>لمزيد من التفاصيل، يُرجى الاطلاع على <a href=\"https://www.aysar.sa/privacy-policy\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">سياسة الخصوصية</a> الخاصة بأيسَر.</p>", "headline": "البيانات والخصوصية"}, {"id": "sec-payment", "content": "<p>تعمل منصة أيسَر وفق نموذج اشتراك مدفوع، وتسري الشروط التالية على جميع المدفوعات:</p>\n<table class=\"policy-table\"><thead><tr><th>البند</th><th>التفاصيل</th></tr></thead><tbody><tr><td><strong>دورة الفوترة</strong></td><td>شهرية أو سنوية حسب الخطة المختارة</td></tr><tr><td><strong>طرق الدفع</strong></td><td>بطاقات الائتمان والمدى، والتحويل البنكي للشركات</td></tr><tr><td><strong>التجديد التلقائي</strong></td><td>يُجدَّد الاشتراك تلقائياً ما لم يُلغَ قبل 48 ساعة من تاريخ التجديد</td></tr><tr><td><strong>سياسة الاسترداد</strong></td><td>لا يُسترد رسوم الاشتراك بعد تفعيله، إلا في حالات استثنائية تُقدّرها أيسَر</td></tr><tr><td><strong>الضريبة</strong></td><td>تخضع جميع الأسعار لضريبة القيمة المضافة 15% وفق نظام الزكاة والضريبة</td></tr></tbody></table>\n<p>في حال التأخر في السداد، تحتفظ أيسَر بحق تعليق الحساب مع إشعار مسبق، واستئناف الخدمة بعد تسوية المستحقات.</p>", "headline": "الاشتراكات والدفع"}, {"id": "sec-ip", "content": "<p>جميع عناصر منصة أيسَر من تصميم وكود وواجهات وشعارات وخوارزميات ومحتوى مرئي — هي ملك حصري لمؤسسة أيسر المتطورة لتقنية المعلومات ومحمية بموجب قوانين الملكية الفكرية في المملكة العربية السعودية.</p>\n<ul class=\"policy-list\"><li>لا يمنح الاشتراك في المنصة أي حقوق ملكية فكرية على أي من عناصرها.</li><li>يُمنح المستخدم ترخيص استخدام محدود وغير حصري وغير قابل للتحويل.</li><li>يحتفظ المستخدم بحقوق الملكية الكاملة على بياناته ومحتواه المُدخَل في المنصة.</li><li>يُحظر إزالة أي إشارات حقوق النشر أو العلامات التجارية من أي جزء من المنصة.</li></ul>", "headline": "الملكية الفكرية"}, {"id": "sec-liability", "content": "<p>تسعى أيسَر جاهدةً لتوفير خدمة موثوقة ومستمرة، غير أنها لا تتحمل المسؤولية عن:</p>\n<ul class=\"policy-list\"><li>الأضرار غير المباشرة أو العرضية الناجمة عن استخدام المنصة أو عدم إمكانية الوصول إليها.</li><li>فقدان البيانات الناجم عن أخطاء المستخدم أو هجمات إلكترونية خارجة عن سيطرة أيسَر.</li><li>الانقطاعات المؤقتة في الخدمة الناجمة عن أعمال الصيانة المجدولة أو الطوارئ.</li><li>دقة البيانات المُدخَلة من قِبل المستخدم أو نتائج القرارات المبنية عليها.</li></ul>\n<p>في جميع الأحوال، لا تتجاوز المسؤولية القصوى لأيسَر قيمة رسوم الاشتراك المدفوعة خلال الثلاثة أشهر السابقة للحادثة.</p>", "headline": "حدود المسؤولية"}, {"id": "sec-termination", "content": "<p>يحق لأي من الطرفين إنهاء الاتفاقية وفق الآتي:</p>\n<ul class=\"policy-list\"><li><strong>إنهاء المستخدم:</strong> يمكن إلغاء الاشتراك في أي وقت من لوحة الإعدادات، وتبقى الخدمة نشطة حتى نهاية الفترة المدفوعة.</li><li><strong>إنهاء أيسَر بسبب مشروع:</strong> في حال انتهاك الشروط يُوقَف الحساب فوراً مع إشعار بالبريد الإلكتروني.</li><li><strong>إنهاء أيسَر بدون سبب:</strong> تُخطر المستخدم قبل 30 يوماً وتُتيح له تصدير بياناته كاملاً.</li><li><strong>بعد الإنهاء:</strong> تُحتفظ البيانات 90 يوماً يمكن خلالها تصديرها، ثم تُحذف نهائياً.</li></ul>", "headline": "إيقاف الخدمة والإنهاء"}, {"id": "sec-law", "content": "<p>تخضع هذه الاتفاقية وتُفسَّر وفقاً لأنظمة ولوائح المملكة العربية السعودية. وفي حال نشوء أي نزاع، يُتّبع المسار التالي:</p>\n<ul class=\"policy-list\"><li><strong>التفاوض الودّي:</strong> يُمنح الطرفان 30 يوماً لتسوية النزاع وديّاً.</li><li><strong>الوساطة:</strong> عند تعذّر الحل الودّي يُلجأ إلى الوساطة عبر جهة معتمدة.</li><li><strong>التحكيم:</strong> في حال عدم الوصول إلى حل، يُحال النزاع إلى هيئة التحكيم التجاري السعودية.</li><li><strong>الاختصاص القضائي:</strong> تختص محاكم مدينة جدة بالفصل في أي نزاعات لم تُحسم بالطرق السابقة.</li></ul>", "headline": "القانون الحاكم وتسوية النزاعات"}, {"id": "sec-changes", "content": "<p>تحتفظ أيسَر بحق تعديل هذه الشروط في أي وقت، وستُخطر المستخدمين المُسجَّلين بالتغييرات الجوهرية عبر:</p>\n<ul class=\"policy-list\"><li>إشعار داخل المنصة قبل 14 يوماً على الأقل من سريان التعديلات.</li><li>رسالة بريد إلكتروني إلى العنوان المسجّل في الحساب.</li></ul>\n<p>يُعدّ استمرار المستخدم في استخدام المنصة بعد سريان التعديلات قبولاً صريحاً للشروط المحدّثة. إن لم تكن موافقاً، يحق لك إنهاء اشتراكك قبل تاريخ السريان.</p>", "headline": "تعديل الشروط"}, {"id": "sec-contact", "content": "<p>لأي استفسار أو ملاحظة تتعلق بهذه الشروط، يمكن التواصل معنا عبر القنوات التالية:</p>\n<ul class=\"policy-list\"><li>&#x1F4E7; البريد الإلكتروني: <a href=\"mailto:legal@aysar.sa\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">legal@aysar.sa</a></li><li>&#x1F4DE; الهاتف: <a href=\"tel:+966125101107\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">966125101107+</a></li><li>&#x1F4AC; واتساب: <a href=\"https://wa.me/966125101107\" target=\"_blank\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">تواصل عبر واتساب</a></li><li>&#x1F310; مركز المساعدة: <a href=\"https://support.aysar.sa/\" target=\"_blank\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">support.aysar.sa</a></li><li>&#x1F4CD; العنوان: جدة، المملكة العربية السعودية</li></ul>\n<div class=\"alert-card green\"><div class=\"alert-icon\">&#x2705;</div><div class=\"alert-body\"><strong>شكراً لثقتك في أيسَر</strong><p>نحن ملتزمون بتقديم خدمة شفافة وموثوقة، وهذه الشروط تعكس التزامنا المشترك ببناء علاقة تجارية ناجحة ومستدامة.</p></div></div>", "headline": "التواصل معنا"}], "route": "/privacy-policy", "title": "سياسة الخصوصية", "entity": "مؤسسة أيسر المتطورة لتقنية المعلومات", "version": "2.1", "breadcrumb": "سياسة الخصوصية", "footerText": "© 2026 مؤسسة أيسر المتطورة لتقنية المعلومات · رقم السجل التجاري: 4030620045\nآخر تحديث لهذه الشروط: مايو 2025 · الإصدار 2.1", "description": "يرجى قراءة سياسة الخصوصية بعناية قبل استخدام منصة أيسَر أو الاشتراك فيها. باستخدامك للمنصة فإنك توافق على الالتزام بجميع ما ورد فيها.", "sidebarCard": {"desc": "فريقنا جاهز للإجابة على أي أسئلة تتعلق بشروط استخدام المنصة.", "href": "mailto:legal@aysar.sa", "title": "لديك استفسار قانوني؟", "linkLabel": "تواصل معنا"}, "effectiveDate": "1 مايو 2025", "footerActions": [{"href": "/privacy-policy", "label": "سياسة الخصوصية", "variant": "ghost"}, {"href": "mailto:legal@aysar.sa", "label": "📧 اتصل بالفريق القانوني", "variant": "primary"}]}', '{"badge": "آخر تحديث: مايو 2025", "parts": [{"id": "sec-intro", "content": "<p>هذه الاتفاقية (\"الشروط\") مبرمة بين <strong>مؤسسة أيسر المتطورة لتقنية المعلومات</strong> (\"أيسَر\"، \"نحن\"، \"الشركة\")، ومقرها المملكة العربية السعودية، رقم السجل التجاري: 4030620045 — وبين الشخص الطبيعي أو الاعتباري الذي يستخدم المنصة (\"المستخدم\"، \"أنت\").</p>\n<p>تشمل \"المنصة\" موقع أيسَر الإلكتروني، تطبيق الجوال، لوحة تحكم المطوّر، نظام CRM، وجميع الخدمات والأدوات المرتبطة.</p>\n<div class=\"alert-card blue\"><div class=\"alert-icon\">&#x2139;&#xFE0F;</div><div class=\"alert-body\"><strong>للعلم</strong><p>تُعدّ هذه الشروط ملزمة لجميع مستخدمي المنصة بمجرد التسجيل أو البدء في الاستخدام، بصرف النظر عن طريقة الوصول.</p></div></div>", "headline": "تعريف الأطراف والمنصة"}, {"id": "sec-accept", "content": "<p>للاشتراك في منصة أيسَر والاستفادة من خدماتها يجب استيفاء الشروط التالية:</p>\n<ul class=\"policy-list\"><li>أن يكون المستخدم شركة أو مؤسسة أو شخصاً اعتبارياً مرخّصاً لمزاولة نشاط التطوير العقاري في المملكة العربية السعودية.</li><li>تقديم بيانات تسجيل صحيحة وكاملة وحديثة، والالتزام بتحديثها فور حدوث أي تغيير.</li><li>الحفاظ على سرية بيانات الدخول (اسم المستخدم وكلمة المرور) وعدم مشاركتها مع أطراف غير مخوّلة.</li><li>قبول هذه الشروط وسياسة الخصوصية بشكل صريح قبل بدء الاستخدام.</li><li>ألا يكون المستخدم قد سبق إيقاف حسابه أو حظره من المنصة لأي سبب.</li></ul>\n<p>تتحمل المنشأة المُسجَّلة المسؤولية الكاملة عن جميع الأنشطة التي تجري تحت حسابها، بما في ذلك تصرفات موظفيها ومستخدميها الفرعيين.</p>", "headline": "شروط القبول والتسجيل"}, {"id": "sec-use", "content": "<p>تُتيح منصة أيسَر للمستخدمين استخدام خدماتها ضمن النطاق التالي حصراً:</p>\n<ul class=\"policy-list\"><li>إدارة المشاريع العقارية وتتبع مراحل الإنشاء وتحديثها.</li><li>التواصل مع العملاء والمشترين وإدارة علاقاتهم عبر نظام CRM المدمج.</li><li>إنشاء صفحات هبوط احترافية واستقبال الحجوزات الإلكترونية.</li><li>إصدار الإشعارات والتقارير الإنشائية الدورية وتوزيعها على العملاء.</li><li>إدارة طلبات الصيانة ومتابعة تنفيذها بعد التسليم.</li><li>الاستفادة من التقارير والإحصاءات التحليلية لاتخاذ قرارات مدروسة.</li></ul>\n<div class=\"alert-card green\"><div class=\"alert-icon\">&#x2705;</div><div class=\"alert-body\"><strong>استخدام مشروع</strong><p>يقتصر الاستخدام المصرّح به على الأنشطة التجارية العقارية المشروعة والمتوافقة مع أنظمة المملكة العربية السعودية.</p></div></div>", "headline": "الاستخدام المسموح به"}, {"id": "sec-forbidden", "content": "<p>يُحظر على المستخدمين القيام بالأنشطة التالية أو السماح بها تحت أي ظرف:</p>\n<ul class=\"policy-list\"><li>نسخ المنصة أو أجزاء منها أو إعادة إنتاجها أو توزيعها دون إذن كتابي مسبق.</li><li>محاولة الوصول غير المصرّح به إلى أنظمة أيسَر أو بيانات مستخدمين آخرين.</li><li>استخدام المنصة لأغراض احتيالية أو مضللة أو مخالفة للأنظمة السعودية.</li><li>نشر أو إدخال برمجيات خبيثة أو محتوى ضار بأي شكل من الأشكال.</li><li>الاستخراج الآلي للبيانات (Scraping) أو استخدام واجهات برمجية غير رسمية دون إذن.</li><li>إعادة بيع الخدمة أو منح حق الوصول إليها لأطراف خارج المنشأة المشتركة.</li><li>التحايل على أي قيود تقنية أو إجراءات أمان مطبّقة على المنصة.</li></ul>\n<div class=\"alert-card amber\"><div class=\"alert-icon\">&#x26A0;&#xFE0F;</div><div class=\"alert-body\"><strong>تحذير</strong><p>يُفضي انتهاك أي من هذه المحظورات إلى إيقاف الحساب فوراً دون إشعار مسبق، وقد تتخذ أيسَر الإجراءات القانونية اللازمة.</p></div></div>", "headline": "الاستخدامات المحظورة"}, {"id": "sec-data", "content": "<p>تُعدّ جميع البيانات التي تُدخلها في المنصة ملكاً للمستخدم، وتلتزم أيسَر بحمايتها والحفاظ على سريتها وفقاً لسياسة الخصوصية المعتمدة ونظام حماية البيانات الشخصية في المملكة العربية السعودية (PDPL).</p>\n<ul class=\"policy-list\"><li>تُخزَّن البيانات على خوادم آمنة داخل المملكة العربية السعودية.</li><li>لا تُباع بيانات المستخدمين أو تُشارَك مع أطراف ثالثة لأغراض تجارية.</li><li>يحق للمستخدم طلب نسخة من بياناته أو حذفها وفق ما تتيحه سياسة الخصوصية.</li><li>تُطبَّق تقنيات تشفير متقدمة لحماية البيانات أثناء النقل والتخزين.</li></ul>\n<p>لمزيد من التفاصيل، يُرجى الاطلاع على <a href=\"https://www.aysar.sa/privacy-policy\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">سياسة الخصوصية</a> الخاصة بأيسَر.</p>", "headline": "البيانات والخصوصية"}, {"id": "sec-payment", "content": "<p>تعمل منصة أيسَر وفق نموذج اشتراك مدفوع، وتسري الشروط التالية على جميع المدفوعات:</p>\n<table class=\"policy-table\"><thead><tr><th>البند</th><th>التفاصيل</th></tr></thead><tbody><tr><td><strong>دورة الفوترة</strong></td><td>شهرية أو سنوية حسب الخطة المختارة</td></tr><tr><td><strong>طرق الدفع</strong></td><td>بطاقات الائتمان والمدى، والتحويل البنكي للشركات</td></tr><tr><td><strong>التجديد التلقائي</strong></td><td>يُجدَّد الاشتراك تلقائياً ما لم يُلغَ قبل 48 ساعة من تاريخ التجديد</td></tr><tr><td><strong>سياسة الاسترداد</strong></td><td>لا يُسترد رسوم الاشتراك بعد تفعيله، إلا في حالات استثنائية تُقدّرها أيسَر</td></tr><tr><td><strong>الضريبة</strong></td><td>تخضع جميع الأسعار لضريبة القيمة المضافة 15% وفق نظام الزكاة والضريبة</td></tr></tbody></table>\n<p>في حال التأخر في السداد، تحتفظ أيسَر بحق تعليق الحساب مع إشعار مسبق، واستئناف الخدمة بعد تسوية المستحقات.</p>", "headline": "الاشتراكات والدفع"}, {"id": "sec-ip", "content": "<p>جميع عناصر منصة أيسَر من تصميم وكود وواجهات وشعارات وخوارزميات ومحتوى مرئي — هي ملك حصري لمؤسسة أيسر المتطورة لتقنية المعلومات ومحمية بموجب قوانين الملكية الفكرية في المملكة العربية السعودية.</p>\n<ul class=\"policy-list\"><li>لا يمنح الاشتراك في المنصة أي حقوق ملكية فكرية على أي من عناصرها.</li><li>يُمنح المستخدم ترخيص استخدام محدود وغير حصري وغير قابل للتحويل.</li><li>يحتفظ المستخدم بحقوق الملكية الكاملة على بياناته ومحتواه المُدخَل في المنصة.</li><li>يُحظر إزالة أي إشارات حقوق النشر أو العلامات التجارية من أي جزء من المنصة.</li></ul>", "headline": "الملكية الفكرية"}, {"id": "sec-liability", "content": "<p>تسعى أيسَر جاهدةً لتوفير خدمة موثوقة ومستمرة، غير أنها لا تتحمل المسؤولية عن:</p>\n<ul class=\"policy-list\"><li>الأضرار غير المباشرة أو العرضية الناجمة عن استخدام المنصة أو عدم إمكانية الوصول إليها.</li><li>فقدان البيانات الناجم عن أخطاء المستخدم أو هجمات إلكترونية خارجة عن سيطرة أيسَر.</li><li>الانقطاعات المؤقتة في الخدمة الناجمة عن أعمال الصيانة المجدولة أو الطوارئ.</li><li>دقة البيانات المُدخَلة من قِبل المستخدم أو نتائج القرارات المبنية عليها.</li></ul>\n<p>في جميع الأحوال، لا تتجاوز المسؤولية القصوى لأيسَر قيمة رسوم الاشتراك المدفوعة خلال الثلاثة أشهر السابقة للحادثة.</p>", "headline": "حدود المسؤولية"}, {"id": "sec-termination", "content": "<p>يحق لأي من الطرفين إنهاء الاتفاقية وفق الآتي:</p>\n<ul class=\"policy-list\"><li><strong>إنهاء المستخدم:</strong> يمكن إلغاء الاشتراك في أي وقت من لوحة الإعدادات، وتبقى الخدمة نشطة حتى نهاية الفترة المدفوعة.</li><li><strong>إنهاء أيسَر بسبب مشروع:</strong> في حال انتهاك الشروط يُوقَف الحساب فوراً مع إشعار بالبريد الإلكتروني.</li><li><strong>إنهاء أيسَر بدون سبب:</strong> تُخطر المستخدم قبل 30 يوماً وتُتيح له تصدير بياناته كاملاً.</li><li><strong>بعد الإنهاء:</strong> تُحتفظ البيانات 90 يوماً يمكن خلالها تصديرها، ثم تُحذف نهائياً.</li></ul>", "headline": "إيقاف الخدمة والإنهاء"}, {"id": "sec-law", "content": "<p>تخضع هذه الاتفاقية وتُفسَّر وفقاً لأنظمة ولوائح المملكة العربية السعودية. وفي حال نشوء أي نزاع، يُتّبع المسار التالي:</p>\n<ul class=\"policy-list\"><li><strong>التفاوض الودّي:</strong> يُمنح الطرفان 30 يوماً لتسوية النزاع وديّاً.</li><li><strong>الوساطة:</strong> عند تعذّر الحل الودّي يُلجأ إلى الوساطة عبر جهة معتمدة.</li><li><strong>التحكيم:</strong> في حال عدم الوصول إلى حل، يُحال النزاع إلى هيئة التحكيم التجاري السعودية.</li><li><strong>الاختصاص القضائي:</strong> تختص محاكم مدينة جدة بالفصل في أي نزاعات لم تُحسم بالطرق السابقة.</li></ul>", "headline": "القانون الحاكم وتسوية النزاعات"}, {"id": "sec-changes", "content": "<p>تحتفظ أيسَر بحق تعديل هذه الشروط في أي وقت، وستُخطر المستخدمين المُسجَّلين بالتغييرات الجوهرية عبر:</p>\n<ul class=\"policy-list\"><li>إشعار داخل المنصة قبل 14 يوماً على الأقل من سريان التعديلات.</li><li>رسالة بريد إلكتروني إلى العنوان المسجّل في الحساب.</li></ul>\n<p>يُعدّ استمرار المستخدم في استخدام المنصة بعد سريان التعديلات قبولاً صريحاً للشروط المحدّثة. إن لم تكن موافقاً، يحق لك إنهاء اشتراكك قبل تاريخ السريان.</p>", "headline": "تعديل الشروط"}, {"id": "sec-contact", "content": "<p>لأي استفسار أو ملاحظة تتعلق بهذه الشروط، يمكن التواصل معنا عبر القنوات التالية:</p>\n<ul class=\"policy-list\"><li>&#x1F4E7; البريد الإلكتروني: <a href=\"mailto:legal@aysar.sa\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">legal@aysar.sa</a></li><li>&#x1F4DE; الهاتف: <a href=\"tel:+966125101107\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">966125101107+</a></li><li>&#x1F4AC; واتساب: <a href=\"https://wa.me/966125101107\" target=\"_blank\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">تواصل عبر واتساب</a></li><li>&#x1F310; مركز المساعدة: <a href=\"https://support.aysar.sa/\" target=\"_blank\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">support.aysar.sa</a></li><li>&#x1F4CD; العنوان: جدة، المملكة العربية السعودية</li></ul>\n<div class=\"alert-card green\"><div class=\"alert-icon\">&#x2705;</div><div class=\"alert-body\"><strong>شكراً لثقتك في أيسَر</strong><p>نحن ملتزمون بتقديم خدمة شفافة وموثوقة، وهذه الشروط تعكس التزامنا المشترك ببناء علاقة تجارية ناجحة ومستدامة.</p></div></div>", "headline": "التواصل معنا"}], "route": "/terms-of-use", "title": "شروط الاستخدام", "entity": "مؤسسة أيسر المتطورة لتقنية المعلومات", "version": "2.1", "breadcrumb": "شروط الاستخدام", "footerText": "© 2026 مؤسسة أيسر المتطورة لتقنية المعلومات · رقم السجل التجاري: 4030620045\nآخر تحديث لهذه الشروط: مايو 2025 · الإصدار 2.1", "description": "يرجى قراءة هذه الشروط بعناية قبل استخدام منصة أيسَر أو الاشتراك فيها. باستخدامك للمنصة فإنك توافق على الالتزام بجميع ما ورد فيها.", "sidebarCard": {"desc": "فريقنا جاهز للإجابة على أي أسئلة تتعلق بشروط استخدام المنصة.", "href": "mailto:legal@aysar.sa", "title": "لديك استفسار قانوني؟", "linkLabel": "تواصل معنا"}, "effectiveDate": "1 مايو 2025", "footerActions": [{"href": "/privacy-policy", "label": "سياسة الخصوصية", "variant": "ghost"}, {"href": "mailto:legal@aysar.sa", "label": "📧 اتصل بالفريق القانوني", "variant": "primary"}]}', '{"badge": "آخر تحديث: مايو 2025", "parts": [{"id": "sec-intro", "content": "<p>هذه الاتفاقية (\"الشروط\") مبرمة بين <strong>مؤسسة أيسر المتطورة لتقنية المعلومات</strong> (\"أيسَر\"، \"نحن\"، \"الشركة\")، ومقرها المملكة العربية السعودية، رقم السجل التجاري: 4030620045 — وبين الشخص الطبيعي أو الاعتباري الذي يستخدم المنصة (\"المستخدم\"، \"أنت\").</p>\n<p>تشمل \"المنصة\" موقع أيسَر الإلكتروني، تطبيق الجوال، لوحة تحكم المطوّر، نظام CRM، وجميع الخدمات والأدوات المرتبطة.</p>\n<div class=\"alert-card blue\"><div class=\"alert-icon\">&#x2139;&#xFE0F;</div><div class=\"alert-body\"><strong>للعلم</strong><p>تُعدّ هذه الشروط ملزمة لجميع مستخدمي المنصة بمجرد التسجيل أو البدء في الاستخدام، بصرف النظر عن طريقة الوصول.</p></div></div>", "headline": "تعريف الأطراف والمنصة"}, {"id": "sec-accept", "content": "<p>للاشتراك في منصة أيسَر والاستفادة من خدماتها يجب استيفاء الشروط التالية:</p>\n<ul class=\"policy-list\"><li>أن يكون المستخدم شركة أو مؤسسة أو شخصاً اعتبارياً مرخّصاً لمزاولة نشاط التطوير العقاري في المملكة العربية السعودية.</li><li>تقديم بيانات تسجيل صحيحة وكاملة وحديثة، والالتزام بتحديثها فور حدوث أي تغيير.</li><li>الحفاظ على سرية بيانات الدخول (اسم المستخدم وكلمة المرور) وعدم مشاركتها مع أطراف غير مخوّلة.</li><li>قبول هذه الشروط وسياسة الخصوصية بشكل صريح قبل بدء الاستخدام.</li><li>ألا يكون المستخدم قد سبق إيقاف حسابه أو حظره من المنصة لأي سبب.</li></ul>\n<p>تتحمل المنشأة المُسجَّلة المسؤولية الكاملة عن جميع الأنشطة التي تجري تحت حسابها، بما في ذلك تصرفات موظفيها ومستخدميها الفرعيين.</p>", "headline": "شروط القبول والتسجيل"}, {"id": "sec-use", "content": "<p>تُتيح منصة أيسَر للمستخدمين استخدام خدماتها ضمن النطاق التالي حصراً:</p>\n<ul class=\"policy-list\"><li>إدارة المشاريع العقارية وتتبع مراحل الإنشاء وتحديثها.</li><li>التواصل مع العملاء والمشترين وإدارة علاقاتهم عبر نظام CRM المدمج.</li><li>إنشاء صفحات هبوط احترافية واستقبال الحجوزات الإلكترونية.</li><li>إصدار الإشعارات والتقارير الإنشائية الدورية وتوزيعها على العملاء.</li><li>إدارة طلبات الصيانة ومتابعة تنفيذها بعد التسليم.</li><li>الاستفادة من التقارير والإحصاءات التحليلية لاتخاذ قرارات مدروسة.</li></ul>\n<div class=\"alert-card green\"><div class=\"alert-icon\">&#x2705;</div><div class=\"alert-body\"><strong>استخدام مشروع</strong><p>يقتصر الاستخدام المصرّح به على الأنشطة التجارية العقارية المشروعة والمتوافقة مع أنظمة المملكة العربية السعودية.</p></div></div>", "headline": "الاستخدام المسموح به"}, {"id": "sec-forbidden", "content": "<p>يُحظر على المستخدمين القيام بالأنشطة التالية أو السماح بها تحت أي ظرف:</p>\n<ul class=\"policy-list\"><li>نسخ المنصة أو أجزاء منها أو إعادة إنتاجها أو توزيعها دون إذن كتابي مسبق.</li><li>محاولة الوصول غير المصرّح به إلى أنظمة أيسَر أو بيانات مستخدمين آخرين.</li><li>استخدام المنصة لأغراض احتيالية أو مضللة أو مخالفة للأنظمة السعودية.</li><li>نشر أو إدخال برمجيات خبيثة أو محتوى ضار بأي شكل من الأشكال.</li><li>الاستخراج الآلي للبيانات (Scraping) أو استخدام واجهات برمجية غير رسمية دون إذن.</li><li>إعادة بيع الخدمة أو منح حق الوصول إليها لأطراف خارج المنشأة المشتركة.</li><li>التحايل على أي قيود تقنية أو إجراءات أمان مطبّقة على المنصة.</li></ul>\n<div class=\"alert-card amber\"><div class=\"alert-icon\">&#x26A0;&#xFE0F;</div><div class=\"alert-body\"><strong>تحذير</strong><p>يُفضي انتهاك أي من هذه المحظورات إلى إيقاف الحساب فوراً دون إشعار مسبق، وقد تتخذ أيسَر الإجراءات القانونية اللازمة.</p></div></div>", "headline": "الاستخدامات المحظورة"}, {"id": "sec-data", "content": "<p>تُعدّ جميع البيانات التي تُدخلها في المنصة ملكاً للمستخدم، وتلتزم أيسَر بحمايتها والحفاظ على سريتها وفقاً لسياسة الخصوصية المعتمدة ونظام حماية البيانات الشخصية في المملكة العربية السعودية (PDPL).</p>\n<ul class=\"policy-list\"><li>تُخزَّن البيانات على خوادم آمنة داخل المملكة العربية السعودية.</li><li>لا تُباع بيانات المستخدمين أو تُشارَك مع أطراف ثالثة لأغراض تجارية.</li><li>يحق للمستخدم طلب نسخة من بياناته أو حذفها وفق ما تتيحه سياسة الخصوصية.</li><li>تُطبَّق تقنيات تشفير متقدمة لحماية البيانات أثناء النقل والتخزين.</li></ul>\n<p>لمزيد من التفاصيل، يُرجى الاطلاع على <a href=\"https://www.aysar.sa/privacy-policy\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">سياسة الخصوصية</a> الخاصة بأيسَر.</p>", "headline": "البيانات والخصوصية"}, {"id": "sec-payment", "content": "<p>تعمل منصة أيسَر وفق نموذج اشتراك مدفوع، وتسري الشروط التالية على جميع المدفوعات:</p>\n<table class=\"policy-table\"><thead><tr><th>البند</th><th>التفاصيل</th></tr></thead><tbody><tr><td><strong>دورة الفوترة</strong></td><td>شهرية أو سنوية حسب الخطة المختارة</td></tr><tr><td><strong>طرق الدفع</strong></td><td>بطاقات الائتمان والمدى، والتحويل البنكي للشركات</td></tr><tr><td><strong>التجديد التلقائي</strong></td><td>يُجدَّد الاشتراك تلقائياً ما لم يُلغَ قبل 48 ساعة من تاريخ التجديد</td></tr><tr><td><strong>سياسة الاسترداد</strong></td><td>لا يُسترد رسوم الاشتراك بعد تفعيله، إلا في حالات استثنائية تُقدّرها أيسَر</td></tr><tr><td><strong>الضريبة</strong></td><td>تخضع جميع الأسعار لضريبة القيمة المضافة 15% وفق نظام الزكاة والضريبة</td></tr></tbody></table>\n<p>في حال التأخر في السداد، تحتفظ أيسَر بحق تعليق الحساب مع إشعار مسبق، واستئناف الخدمة بعد تسوية المستحقات.</p>", "headline": "الاشتراكات والدفع"}, {"id": "sec-ip", "content": "<p>جميع عناصر منصة أيسَر من تصميم وكود وواجهات وشعارات وخوارزميات ومحتوى مرئي — هي ملك حصري لمؤسسة أيسر المتطورة لتقنية المعلومات ومحمية بموجب قوانين الملكية الفكرية في المملكة العربية السعودية.</p>\n<ul class=\"policy-list\"><li>لا يمنح الاشتراك في المنصة أي حقوق ملكية فكرية على أي من عناصرها.</li><li>يُمنح المستخدم ترخيص استخدام محدود وغير حصري وغير قابل للتحويل.</li><li>يحتفظ المستخدم بحقوق الملكية الكاملة على بياناته ومحتواه المُدخَل في المنصة.</li><li>يُحظر إزالة أي إشارات حقوق النشر أو العلامات التجارية من أي جزء من المنصة.</li></ul>", "headline": "الملكية الفكرية"}, {"id": "sec-liability", "content": "<p>تسعى أيسَر جاهدةً لتوفير خدمة موثوقة ومستمرة، غير أنها لا تتحمل المسؤولية عن:</p>\n<ul class=\"policy-list\"><li>الأضرار غير المباشرة أو العرضية الناجمة عن استخدام المنصة أو عدم إمكانية الوصول إليها.</li><li>فقدان البيانات الناجم عن أخطاء المستخدم أو هجمات إلكترونية خارجة عن سيطرة أيسَر.</li><li>الانقطاعات المؤقتة في الخدمة الناجمة عن أعمال الصيانة المجدولة أو الطوارئ.</li><li>دقة البيانات المُدخَلة من قِبل المستخدم أو نتائج القرارات المبنية عليها.</li></ul>\n<p>في جميع الأحوال، لا تتجاوز المسؤولية القصوى لأيسَر قيمة رسوم الاشتراك المدفوعة خلال الثلاثة أشهر السابقة للحادثة.</p>", "headline": "حدود المسؤولية"}, {"id": "sec-termination", "content": "<p>يحق لأي من الطرفين إنهاء الاتفاقية وفق الآتي:</p>\n<ul class=\"policy-list\"><li><strong>إنهاء المستخدم:</strong> يمكن إلغاء الاشتراك في أي وقت من لوحة الإعدادات، وتبقى الخدمة نشطة حتى نهاية الفترة المدفوعة.</li><li><strong>إنهاء أيسَر بسبب مشروع:</strong> في حال انتهاك الشروط يُوقَف الحساب فوراً مع إشعار بالبريد الإلكتروني.</li><li><strong>إنهاء أيسَر بدون سبب:</strong> تُخطر المستخدم قبل 30 يوماً وتُتيح له تصدير بياناته كاملاً.</li><li><strong>بعد الإنهاء:</strong> تُحتفظ البيانات 90 يوماً يمكن خلالها تصديرها، ثم تُحذف نهائياً.</li></ul>", "headline": "إيقاف الخدمة والإنهاء"}, {"id": "sec-law", "content": "<p>تخضع هذه الاتفاقية وتُفسَّر وفقاً لأنظمة ولوائح المملكة العربية السعودية. وفي حال نشوء أي نزاع، يُتّبع المسار التالي:</p>\n<ul class=\"policy-list\"><li><strong>التفاوض الودّي:</strong> يُمنح الطرفان 30 يوماً لتسوية النزاع وديّاً.</li><li><strong>الوساطة:</strong> عند تعذّر الحل الودّي يُلجأ إلى الوساطة عبر جهة معتمدة.</li><li><strong>التحكيم:</strong> في حال عدم الوصول إلى حل، يُحال النزاع إلى هيئة التحكيم التجاري السعودية.</li><li><strong>الاختصاص القضائي:</strong> تختص محاكم مدينة جدة بالفصل في أي نزاعات لم تُحسم بالطرق السابقة.</li></ul>", "headline": "القانون الحاكم وتسوية النزاعات"}, {"id": "sec-changes", "content": "<p>تحتفظ أيسَر بحق تعديل هذه الشروط في أي وقت، وستُخطر المستخدمين المُسجَّلين بالتغييرات الجوهرية عبر:</p>\n<ul class=\"policy-list\"><li>إشعار داخل المنصة قبل 14 يوماً على الأقل من سريان التعديلات.</li><li>رسالة بريد إلكتروني إلى العنوان المسجّل في الحساب.</li></ul>\n<p>يُعدّ استمرار المستخدم في استخدام المنصة بعد سريان التعديلات قبولاً صريحاً للشروط المحدّثة. إن لم تكن موافقاً، يحق لك إنهاء اشتراكك قبل تاريخ السريان.</p>", "headline": "تعديل الشروط"}, {"id": "sec-contact", "content": "<p>لأي استفسار أو ملاحظة تتعلق بهذه الشروط، يمكن التواصل معنا عبر القنوات التالية:</p>\n<ul class=\"policy-list\"><li>&#x1F4E7; البريد الإلكتروني: <a href=\"mailto:legal@aysar.sa\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">legal@aysar.sa</a></li><li>&#x1F4DE; الهاتف: <a href=\"tel:+966125101107\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">966125101107+</a></li><li>&#x1F4AC; واتساب: <a href=\"https://wa.me/966125101107\" target=\"_blank\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">تواصل عبر واتساب</a></li><li>&#x1F310; مركز المساعدة: <a href=\"https://support.aysar.sa/\" target=\"_blank\" style=\"color:var(--color-indigo);font-weight:600;text-decoration:none\">support.aysar.sa</a></li><li>&#x1F4CD; العنوان: جدة، المملكة العربية السعودية</li></ul>\n<div class=\"alert-card green\"><div class=\"alert-icon\">&#x2705;</div><div class=\"alert-body\"><strong>شكراً لثقتك في أيسَر</strong><p>نحن ملتزمون بتقديم خدمة شفافة وموثوقة، وهذه الشروط تعكس التزامنا المشترك ببناء علاقة تجارية ناجحة ومستدامة.</p></div></div>", "headline": "التواصل معنا"}], "route": "/return-policy", "title": "سياسة الاسترجاع", "entity": "مؤسسة أيسر المتطورة لتقنية المعلومات", "version": "2.1", "breadcrumb": "سياسة الاسترجاع", "footerText": "© 2026 مؤسسة أيسر المتطورة لتقنية المعلومات · رقم السجل التجاري: 4030620045\nآخر تحديث لهذه الشروط: مايو 2025 · الإصدار 2.1", "description": "يرجى قراءة سياسة الاسترجاع بعناية قبل استخدام منصة أيسَر أو الاشتراك فيها. باستخدامك للمنصة فإنك توافق على الالتزام بجميع ما ورد فيها.", "sidebarCard": {"desc": "فريقنا جاهز للإجابة على أي أسئلة تتعلق بشروط استخدام المنصة.", "href": "mailto:legal@aysar.sa", "title": "لديك استفسار قانوني؟", "linkLabel": "تواصل معنا"}, "effectiveDate": "1 مايو 2025", "footerActions": [{"href": "/privacy-policy", "label": "سياسة الخصوصية", "variant": "ghost"}, {"href": "mailto:legal@aysar.sa", "label": "📧 اتصل بالفريق القانوني", "variant": "primary"}]}', '2026-05-24 01:22:39.199');


